                res.push(val);
                i += 1;
            } else {
                // Pick from v2
                let val = v2[j];
                proof {
                    lemma_sorted_snoc(res@, val);
                    // Proving permutation:
                    // new_consumed = v1[..i] + v2[..j+1]
                    // consumed + val = v1[..i] + v2[..j] + v2[j]
                    // By associativity, these are equal sequences.
                    lemma_perm_append(consumed, res@, val);
                }
                res.push(val);
                j += 1;
            }
        }
        res
    }
    // </proofs>

    // Following is the block for the main specification
    // <spec>
    fn merge_sort(v: &mut Vec<i32>)
        ensures
            is_sorted(v@),
            is_permutation(old(v)@, v@),
        decreases v.len()
    // </spec>
    // <code>
    {
        let n = v.len();
        if n <= 1 {
