            return;
        }

        let mid = n / 2;
        let mut left = Vec::new();
        let mut right = Vec::new();

        let ghost original_v = v@;

        // Split v into left and right
        let mut k = 0;
        while k < mid 
            invariant 0 <= k <= mid, left@ == original_v.subrange(0, k as int)
        {
            left.push(v[k]);
            k += 1;
        }

        let mut m = mid;
        while m < n
            invariant mid <= m <= n, right@ == original_v.subrange(mid as int, m as int)
        {
            right.push(v[m]);
            m += 1;
        }

        // Prove v == left + right
        assert(v@ =~= left@ + right@);

        let ghost old_left = left@;
        let ghost old_right = right@;

        // Recursive calls
        merge_sort(&mut left);
        merge_sort(&mut right);

        // Combine permutations
        proof {
            // is_perm(old_left, left) && is_perm(old_right, right) => is_perm(old_left+old_right, left+right)
            lemma_perm_concat(old_left, old_right, left@, right@);
        }

        // Merge
        let res = merge(&left, &right);

        // Final permutation proof
        proof {
            // we have is_perm(original_v, left + right) (from concat lemma and v = l+r)
            // we have is_perm(left + right, res) (from merge spec)
            lemma_perm_trans(original_v, left@ + right@, res@);
        }

        *v = res;
    }
    // </code>

