                // All elements in res are smaller or equal to remaining elements in v1 and v2
                forall|k| 0 <= k < res.len() ==> (i < v1.len() ==> res@[k] <= v1@[i as int]),
                forall|k| 0 <= k < res.len() ==> (j < v2.len() ==> res@[k] <= v2@[j as int]),
            decreases (v1.len() - i) + (v2.len() - j)
        {
            let ghost old_res = res@;
            let ghost consumed = v1_seq.subrange(0, i as int) + v2_seq.subrange(0, j as int);

            if i < v1.len() && (j == v2.len() || v1[i] <= v2[j]) {
                // Pick from v1
                let val = v1[i];
                proof {
                    lemma_sorted_snoc(res@, val);
                    // consumed + val = (v1[..i] + v2[..j]) + val
                    // new_consumed   = v1[..i+1] + v2[..j] = (v1[..i] + val) + v2[..j]

                    // Step 1: Append val to both sides of hypothesis (consumed ~ res)
                    lemma_perm_append(consumed, res@, val); 
                    // Now: is_perm(consumed + val, res + val)

                    // Step 2: Show new_consumed is permutation of consumed + val
                    // lemma_perm_move_element proves: is_perm( (a+x)+b, (a+b)+x )
                    // i.e., is_perm(new_consumed, consumed + val)
                    lemma_perm_move_element(v1_seq.subrange(0, i as int), v2_seq.subrange(0, j as int), val);

                    // Step 3: Transitivity
                    lemma_perm_trans(v1_seq.subrange(0, (i+1) as int) + v2_seq.subrange(0, j as int), consumed.push(val), res@.push(val));
                }
                res.push(val);
                i += 1;
            } else {
                // Pick from v2
                let val = v2[j];
                proof {
                    lemma_sorted_snoc(res@, val);
                    lemma_perm_append(consumed, res@, val);
                }
                res.push(val);
                j += 1;
            }
        }
        res
    }
    // </proofs>

    // Following is the block for the main specification
    // <spec>
    fn merge_sort(v: &mut Vec<i32>)
        ensures
            is_sorted(v@),
            is_permutation(old(v)@, v@),
        decreases old(v)@.len()
    // </spec>
    // <code>
    {
        let n = v.len();
        if n <= 1 {
            proof { lemma_perm_refl(v@); }
            return;
        }

        let mid = n / 2;
        let mut left = Vec::new();
        let mut right = Vec::new();

        let ghost original_v = v@;

        // Split v into left and right
        let mut k: usize = 0;
        while k < mid 
            invariant 0 <= k <= mid, left@ == original_v.subrange(0, k as int)
            decreases mid - k
        {
            left.push(v[k]);
            k += 1;
        }

        let mut m: usize = mid;
        while m < n
            invariant mid <= m <= n, right@ == original_v.subrange(mid as int, m as int)
            decreases n - m
        {
            right.push(v[m]);
            m += 1;
        }

        // Prove v == left + right
        assert(v@ =~= left@ + right@);

        let ghost old_left = left@;
        let ghost old_right = right@;

        // Recursive calls
        merge_sort(&mut left);
        merge_sort(&mut right);

        // Combine permutations
        proof {
            // is_perm(old_left, left) && is_perm(old_right, right) => is_perm(old_left+old_right, left+right)
            lemma_perm_concat(old_left, old_right, left@, right@);
        }

        // Merge
        let res = merge(&left, &right);

        // Final permutation proof
        proof {
            // we have is_perm(original_v, left + right) (from concat lemma and v = l+r)
            // we have is_perm(left + right, res) (from merge spec)
            lemma_perm_trans(original_v, left@ + right@, res@);
        }

        *v = res;
    }
    // </code>

    #[verifier::external]
    fn main() {
        let mut v = vec![5, 1, 4, 2, 8];
        let ghost original_v = v@;

        merge_sort(&mut v);

        assert(is_sorted(v@));
        assert(is_permutation(original_v, v@));
    }
