        let n1 = s1.len();
        let n2 = s2.len();
        let p = Seq::new(n1 + n2, |i: int| if i < n1 { p1[i] } else { p2[i - n1] + (n1 as int) });

        assert(is_valid_index_permutation(p, (n1 + n2) as int));
