        if n <= 1 {
            proof { lemma_perm_refl(v@); }
            return;
        }

        let mid = n / 2;
        let mut left = Vec::new();
        let mut right = Vec::new();

        let ghost original_v = v@;

        let mut k: usize = 0;
        while k < mid 
            invariant 
                0 <= k <= mid, 
                n == v.len(),
                mid <= n,
                left@ == original_v.subrange(0, k as int),
                v@ == original_v
            decreases mid - k
        {
            let val = v[k];
            left.push(val);
            proof {
                lemma_subrange_next(original_v, k as int);
            }
            k += 1;
        }

        let mut m: usize = mid;
        while m < n
            invariant 
                mid <= m <= n, 
                n == v.len(),
                right@ == original_v.subrange(mid as int, m as int),
                v@ == original_v
            decreases n - m
        {
            let val = v[m];
            right.push(val);
            proof {
                lemma_subrange_next(original_v, m as int);
            }
            m += 1;
        }

        assert(v@ =~= left@ + right@);

        let ghost old_left = left@;
        let ghost old_right = right@;

        merge_sort(&mut left);
        merge_sort(&mut right);

        proof {
            lemma_perm_concat(old_left, old_right, left@, right@);
        }

        let res = merge(&left, &right);

        proof {
            lemma_perm_trans(original_v, left@ + right@, res@);
        }

        *v = res;
    }
    // </code>

    #[verifier::external]
    fn main() {
        let mut v = vec![5, 1, 4, 2, 8];
        let ghost original_v = v@;

        merge_sort(&mut v);

        assert(is_sorted(v@));
        assert(is_permutation(original_v, v@));
    }
